    return f'{weather.data.get("main").get("temp")}K'

def get_weather_from_ip(ip):
    coords = requests.get(f'https://ipapi.co/{ip}/json')
    latitude = coords.json().get('latitude')
    longitude = coords.json().get('longitude')
    return get_weather(latitude, longitude)

