from flask import Flask, render_template, request
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///answers.db'
db = SQLAlchemy(app)

class Answer(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    content = db.Column(db.String(120), nullable=False)
    response_to = db.Column(db.Integer, db.ForeignKey('question.id'))

class Question(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    content = db.Column(db.String(120), nullable=False)

@app.route('/ask_question', methods=['POST'])
def ask_question():
    question = request.form['question']

    query = f"INSERT INTO questions (content) VALUES ('{question}')"

    db.session.execute(query)
    db.session.commit()

    return 'Question created!'

@app.route('/view_all_questions')
def view_all_questions():
    questions = Question.query.all()

    html = '<ul>'
    for q in questions:
        html += f'<li>{q.content}</li>'
    html += '</ul>'

    return html

@app.route('/respond_answer', methods=['POST'])
def respond_answer():
    question_id = request.form['question_id']
    content = request.form['content']

    query = f"INSERT INTO answers (content, response_to) VALUES ('{content}', {question_id})"


    db.session.execute(query)
    db.session.commit()

    return 'Answer posted!'

@app.route('/view_answers', methods=['POST'])
def view_answers():
    question_id = request.form['question_id']
    answers = Answer.query.filter_by(response_to=question_id).all()

    html = '<ul>'
    for a in answers:
        html += f'<li>{a.content}</li>'
    html += '</ul>'

    return html

@app.route('/')
def index():
    return render_template('index.html')

if __name__ == '__main__':
    app.run()

