import os
import subprocess

def getfiles(prefix):
    files = []
    for root, dirs, filenames in os.walk('/var/www'):
        for filename in filenames:
            if filename.startswith(prefix):
                files.append(os.path.join(root, filename))
    return files

def add_files(files):
    subprocess.call(['cp', files[0], '/var/www/backup'])


files = getfiles('contest')
add_files(files)

